+func (h *GitOpsHandlers) GetArgoHealthSummary(c *fiber.Ctx) error {
+	if h.k8sClient == nil {
+		return c.Status(503).JSON(fiber.Map{
+			"error":   "Kubernetes client not configured",
+			"isDemoData": true,
+		})
